INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-6f0ba476-moex-00094', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「畫家在素描時，勒定了所畫對象大約的輪廓後，只以炭筆磨擦出光影的陰暗與明亮，而不 做細部的描繪，保持一點朦朧感，以免整個畫面過於呆板。這個階段，就像詩一樣，在光與 暗、有與無之間，帶著一點迷濛，一點神祕，一點耐人追索的況味。然而這並非脫離現實， 仔細想想，我們在人生裡，大多數的情感都是這樣迷濛的吧！誰能肯定自己的內心無論是哪 一刻都清晰無比的呢？」 根據上文，下列選項正確的是：', '["擅長讀詩的人擁有最單純的心思，對世事經常感到懵懵懂懂", "詩在指涉、內涵上的模糊性，常能帶給讀者解釋探索的趣味", "詩與素描一樣，都不可進行細部描繪，才能提升整體的美感", "思緒清明的人難以享受讀詩之樂，因複雜處能輕易迎刃而解 生命中多數情感一如詩般迷濛，從詩中可以體會人生與現實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00095', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「ChatGPT或Bing Chat多是提供定義式的短語，回覆的內容主要是『已知』的有限資訊， 難以『多義性』的語言表現感知複雜的人類思維。這是因為 AI 的訓練出自設計者目前的偏 好或定見，如果想讓AI更貼近人類需求，就必須仰賴人類持續更新且多樣化的經驗。」 根據上文，下列選項正確的是：', '["目前AI程式設計者偏好取樣多元的生活經驗", "AI現在仍未取代人類思想情感的複雜性表現", "AI設計者皆偏愛不受感知影響的科學性語言", "目前AI是以短語提供快速單一的資訊為目的 不斷轉型的語言文化和科技趨勢無直接關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00096', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '稅捐稽徵法所稱之稅捐，不包括：', '["關稅", "地價稅", "遺產稅", "特種貨物及勞務稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "34e7049037ce", "answer_pdf_sha1": "6813b7e945be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00097', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法之規定，關於稅捐的徵收，下列何者沒有優先於抵押權？', '["綜合所得稅", "土地增值稅", "地價稅", "房屋稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "34e7049037ce", "answer_pdf_sha1": "6813b7e945be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00098', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法之規定，稅捐的徵收期間原則上為幾年？', '["3年", "5年", "7年", "9年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "34e7049037ce", "answer_pdf_sha1": "6813b7e945be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00099', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依現行稅捐稽徵法之規定，逾期繳納稅捐，每逾幾日按滯納數額加徵百分之一滯納金？', '["1日", "2日", "3日", "4日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "34e7049037ce", "answer_pdf_sha1": "6813b7e945be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00100', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法之規定，因可歸責於政府機關之錯誤，致溢繳稅款者，其退稅請求權自繳納之日起幾年間不 行使而消滅？', '["15年", "5年", "10年", "2年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "34e7049037ce", "answer_pdf_sha1": "6813b7e945be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00101', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依現行所得稅法之規定，下列何者不是免稅所得？', '["傷害或死亡之損害賠償金", "人身保險之保險給付", "因繼承而取得之財產", "國民小學之教職員薪資"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:38+00:00", "source_pdf_sha1": "34e7049037ce", "answer_pdf_sha1": "6813b7e945be", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
